import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Stack,
  Alert,
  Snackbar,
  CircularProgress,
  LinearProgress,
  useTheme,
  FormControlLabel,
  Switch,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  FormHelperText,
  Chip
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon,
  Refresh as RefreshIcon
} from '@mui/icons-material';
import { getRules, createRule, updateRule, deleteRule, getNodes, getNodeGroups, getRuleSets, createRuleSet, updateRuleSet, deleteRuleSet, updateRuleSetRules } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Rules = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [rules, setRules] = useState([]);
  const [nodes, setNodes] = useState([]);
  const [nodeGroups, setNodeGroups] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedRule, setSelectedRule] = useState(null);
  const [editRule, setEditRule] = useState({
    name: '',
    type: 'custom',
    url: '',
    rules: [],
    outbound: 'direct',
    nodeGroup: '',
    specificNode: '',
    enabled: true,
    format: 'domain',
    description: '',
  });
  const [ruleSets, setRuleSets] = useState([]);

  const outboundTypes = [
    { value: 'direct', label: '直连', description: '不走代理直接连接' },
    { value: 'reject', label: '拒绝', description: '通过DNS拒绝连接' },
    { value: 'node_group', label: '节点组', description: '使用指定节点组' },
    { value: 'specific', label: '指定节点', description: '使用特定节点' },
  ];

  const ruleTypes = [
    { value: 'custom', label: '自定义规则', description: '手动添加规则' },
    { value: 'ruleset', label: '远程规则集', description: '导入SRS或JSON格式的规则集' },
  ];

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [rulesData, nodesData, groupsData, ruleSetsData] = await Promise.all([
        getRules(),
        getNodes(),
        getNodeGroups(),
        getRuleSets()
      ]);
      setRules(rulesData);
      setNodes(nodesData);
      setNodeGroups(groupsData);
      setRuleSets(ruleSetsData);
      setError(null);
    } catch (err) {
      setError(err.response?.data?.error || '获取数据失败');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (rule = null) => {
    if (rule) {
      setSelectedRule(rule);
      setEditRule({
        ...rule,
        type: rule.type === 'ruleset' ? 'ruleset' : 'custom',
        rules: rule.domains || rule.ips || [],
        enabled: rule.enabled ?? true,
        format: rule.format || 'domain',
      });
    } else {
      setSelectedRule(null);
      setEditRule({
        name: '',
        type: 'custom',
        url: '',
        rules: [],
        outbound: 'direct',
        nodeGroup: '',
        specificNode: '',
        enabled: true,
        format: 'domain',
        description: '',
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedRule(null);
    setEditRule({
      name: '',
      type: 'custom',
      url: '',
      rules: [],
      outbound: 'direct',
      nodeGroup: '',
      specificNode: '',
      enabled: true,
      format: 'domain',
      description: '',
    });
  };

  const handleSaveRule = async () => {
    try {
      setLoading(true);
      if (editRule.type === 'ruleset') {
        // 保存为规则集
        const ruleSetData = {
          name: editRule.name,
          url: editRule.url,
          type: editRule.type === 'srs' ? 'srs' : 'json', // 根据选择的格式设置类型
          format: editRule.format,
          outbound: editRule.outbound,
          description: editRule.description,
          enabled: editRule.enabled,
        };

        if (selectedRule) {
          await updateRuleSet(selectedRule.id, ruleSetData);
        } else {
          await createRuleSet(ruleSetData);
        }
      } else {
        // 保存为普通规则
        const ruleData = {
          name: editRule.name,
          type: editRule.format, // 使用 format 作为规则类型
          domains: editRule.format === 'domain' ? editRule.rules : [],
          ips: editRule.format === 'geoip' ? editRule.rules : [],
          outbound: editRule.outbound,
          nodeGroup: editRule.nodeGroup,
          specificNode: editRule.specificNode,
          enabled: editRule.enabled,
          description: editRule.description,
        };

        if (selectedRule) {
          await updateRule(selectedRule.id, ruleData);
        } else {
          await createRule(ruleData);
        }
      }
      await fetchData();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError(err.response?.data?.error || '保存失败');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      // 在规则集列表中查找
      const ruleSet = ruleSets.find(rs => rs.id === id);
      if (ruleSet) {
        await deleteRuleSet(id);
      } else {
        await deleteRule(id);
      }
      await fetchData();
      setSuccess(true);
    } catch (err) {
      setError(err.response?.data?.error || '删除失败');
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateRuleSet = async (id) => {
    try {
      setLoading(true);
      await updateRuleSetRules(id);
      setSuccess(true);
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.error || '更新规则集失败');
    } finally {
      setLoading(false);
    }
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  // 统一规则卡片渲染函数
  const renderRuleCard = (item, type = 'rule') => {
    const isRuleSet = type === 'ruleset';
    const chipLabel = isRuleSet ? item.format : item.type;
    const chipBackground = () => {
      if (isRuleSet) {
        return item.format === 'domain'
          ? 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)'
          : 'linear-gradient(45deg, #42a5f5 30%, #64b5f6 90%)';
      } else {
        return item.type === 'domain'
          ? 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)'
          : item.type === 'ip'
            ? 'linear-gradient(45deg, #42a5f5 30%, #64b5f6 90%)'
            : 'linear-gradient(45deg, #66bb6a 30%, #81c784 90%)';
      }
    };

    // 获取规则来源标签
    const getSourceLabel = () => {
      if (!isRuleSet) {
        return item.type === 'remote' ? '远程规则' : '自定义规则';
      }
      return item.type === 'srs' ? 'SingBox规则集' : 'JSON规则集';
    };

    // 获取规则来源标签颜色
    const getSourceChipColor = () => {
      if (!isRuleSet) {
        return item.type === 'remote'
          ? 'linear-gradient(45deg, #ff9800 30%, #ffa726 90%)'  // 橙色渐变
          : 'linear-gradient(45deg, #9c27b0 30%, #ba68c8 90%)'; // 紫色渐变
      }
      return item.type === 'srs'
        ? 'linear-gradient(45deg, #00bcd4 30%, #4dd0e1 90%)'  // 青色渐变
        : 'linear-gradient(45deg, #ff5722 30%, #ff7043 90%)'; // 深橙色渐变
    };

    return (
      <Grid item xs={12} sm={6} md={4} key={item.id}>
        <Card sx={styles.card}>
          <CardContent>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
              <Typography variant="h6" sx={{ fontWeight: 500 }}>
                {item.name}
              </Typography>
              <Stack direction="row" spacing={1}>
                <IconButton
                  size="small"
                  onClick={() => handleOpenDialog(item)}
                  sx={{
                    color: 'primary.main',
                    '&:hover': {
                      backgroundColor: 'action.hover',
                    },
                  }}
                >
                  <EditIcon fontSize="small" />
                </IconButton>
                <IconButton
                  size="small"
                  onClick={() => handleDelete(item.id)}
                  sx={{
                    color: 'error.main',
                    '&:hover': {
                      backgroundColor: 'action.hover',
                    },
                  }}
                >
                  <DeleteIcon fontSize="small" />
                </IconButton>
                {isRuleSet && (
                  <IconButton
                    size="small"
                    onClick={() => handleUpdateRuleSet(item.id)}
                    sx={{
                      color: 'warning.main',
                      '&:hover': {
                        backgroundColor: 'action.hover',
                      },
                    }}
                  >
                    <RefreshIcon fontSize="small" />
                  </IconButton>
                )}
              </Stack>
            </Box>

            <Stack spacing={1}>
              <Box>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {isRuleSet ? '规则集类型' : '匹配规则'}
                </Typography>
                <Typography variant="body1">
                  {isRuleSet 
                    ? (item.type === 'srs' ? 'Sing-box 规则集' : 'JSON 规则集')
                    : item.pattern}
                </Typography>
              </Box>

              <Box>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {isRuleSet ? '目标出口' : '目标节点'}
                </Typography>
                <Typography variant="body1">
                  {isRuleSet ? item.outbound : item.target}
                </Typography>
              </Box>

              <Stack direction="row" spacing={1} sx={{ mt: 1 }}>
                <Chip 
                  label={chipLabel}
                  size="small"
                  sx={{
                    background: chipBackground,
                    color: '#fff',
                    fontWeight: 500,
                  }}
                />
                <Chip 
                  label={getSourceLabel()}
                  size="small"
                  sx={{
                    background: getSourceChipColor(),
                    color: '#fff',
                    fontWeight: 500,
                  }}
                />
                <Chip 
                  label={item.enabled ? "已启用" : "已禁用"} 
                  size="small"
                  sx={item.enabled ? {
                    ...styles.chip.success,
                    background: 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)',
                    color: '#fff',
                    fontWeight: 500,
                  } : {
                    ...styles.chip.error,
                    background: 'linear-gradient(45deg, #f44336 30%, #e57373 90%)',
                    color: '#fff',
                    fontWeight: 500,
                  }}
                />
              </Stack>

              {isRuleSet && item.description && (
                <Box>
                  <Typography variant="body2" color="text.secondary" gutterBottom>
                    描述
                  </Typography>
                  <Typography variant="body2" sx={{ color: 'text.secondary', fontStyle: 'italic' }}>
                    {item.description}
                  </Typography>
                </Box>
              )}
            </Stack>
          </CardContent>
        </Card>
      </Grid>
    );
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                规则管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={styles.iconButton}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Box sx={{ mb: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h6">规则列表</Typography>
        <Button
          variant="contained"
          size="small"
          startIcon={<AddIcon />}
          onClick={() => handleOpenDialog()}
          sx={styles.actionButton}
        >
          添加规则
        </Button>
      </Box>

      <Grid container spacing={1.5}>
        {rules.map((rule) => renderRuleCard(rule, 'rule'))}
        {ruleSets.map((ruleSet) => renderRuleCard(ruleSet, 'ruleset'))}
      </Grid>

      <Dialog 
        open={openDialog} 
        onClose={handleCloseDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>
          {selectedRule ? '编辑规则' : '添加规则'}
        </DialogTitle>
        <DialogContent>
          <Box mt={2}>
            <TextField
              fullWidth
              label="名称"
              value={editRule.name}
              onChange={(e) => setEditRule({ ...editRule, name: e.target.value })}
              margin="normal"
              required
            />
            <FormControl fullWidth margin="normal">
              <InputLabel>规则类型</InputLabel>
              <Select
                value={editRule.type}
                onChange={(e) => {
                  const newType = e.target.value;
                  setEditRule(prev => ({
                    ...prev,
                    type: newType,
                    format: newType === 'ruleset' ? 'srs' : 'domain',
                    rules: []
                  }));
                }}
                label="规则类型"
              >
                {ruleTypes.map(type => (
                  <MenuItem key={type.value} value={type.value}>
                    {type.label}
                  </MenuItem>
                ))}
              </Select>
              <FormHelperText>{ruleTypes.find(t => t.value === editRule.type)?.description}</FormHelperText>
            </FormControl>

            {editRule.type === 'ruleset' && (
              <>
                <FormControl fullWidth margin="normal">
                  <InputLabel>规则集格式</InputLabel>
                  <Select
                    value={editRule.format}
                    onChange={(e) => setEditRule({ ...editRule, format: e.target.value })}
                    label="规则集格式"
                  >
                    <MenuItem value="srs">SingBox规则集 (.srs)</MenuItem>
                    <MenuItem value="json">JSON规则集 (.json)</MenuItem>
                  </Select>
                </FormControl>
                <TextField
                  fullWidth
                  label="URL"
                  value={editRule.url}
                  onChange={(e) => setEditRule({ ...editRule, url: e.target.value })}
                  margin="normal"
                  required
                />
              </>
            )}

            {editRule.type === 'custom' && (
              <>
                <FormControl fullWidth margin="normal">
                  <InputLabel>规则格式</InputLabel>
                  <Select
                    value={editRule.format}
                    onChange={(e) => setEditRule({ ...editRule, format: e.target.value, rules: [] })}
                    label="规则格式"
                  >
                    <MenuItem value="domain">域名</MenuItem>
                    <MenuItem value="geoip">GeoIP</MenuItem>
                  </Select>
                </FormControl>
                <TextField
                  fullWidth
                  label="规则"
                  value={editRule.rules.join('\n')}
                  onChange={(e) => setEditRule({ ...editRule, rules: e.target.value.split('\n').filter(Boolean) })}
                  margin="normal"
                  multiline
                  rows={4}
                  required
                  helperText={`每行一个${editRule.format === 'domain' ? '域名' : 'IP'}`}
                />
              </>
            )}

            <FormControl fullWidth margin="normal">
              <InputLabel>出站方式</InputLabel>
              <Select
                value={editRule.outbound}
                onChange={(e) => setEditRule({ ...editRule, outbound: e.target.value })}
                label="出站方式"
              >
                {outboundTypes.map(type => (
                  <MenuItem key={type.value} value={type.value}>
                    {type.label}
                  </MenuItem>
                ))}
              </Select>
              <FormHelperText>{outboundTypes.find(t => t.value === editRule.outbound)?.description}</FormHelperText>
            </FormControl>

            {editRule.outbound === 'node_group' && (
              <FormControl fullWidth margin="normal">
                <InputLabel>节点组</InputLabel>
                <Select
                  value={editRule.nodeGroup}
                  onChange={(e) => setEditRule({ ...editRule, nodeGroup: e.target.value })}
                  label="节点组"
                >
                  {nodeGroups.map(group => (
                    <MenuItem key={group.id} value={group.id}>
                      {group.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            )}

            {editRule.outbound === 'specific' && (
              <FormControl fullWidth margin="normal">
                <InputLabel>指定节点</InputLabel>
                <Select
                  value={editRule.specificNode}
                  onChange={(e) => setEditRule({ ...editRule, specificNode: e.target.value })}
                  label="指定节点"
                >
                  {nodes.map(node => (
                    <MenuItem key={node.id} value={node.id}>
                      {node.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            )}

            <TextField
              fullWidth
              label="描述"
              value={editRule.description}
              onChange={(e) => setEditRule({ ...editRule, description: e.target.value })}
              margin="normal"
              multiline
              rows={2}
            />

            <FormControlLabel
              control={
                <Switch
                  checked={editRule.enabled}
                  onChange={(e) => setEditRule({ ...editRule, enabled: e.target.checked })}
                />
              }
              label="启用"
              sx={{ mt: 2 }}
            />
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog}>取消</Button>
          <Button onClick={handleSaveRule} variant="contained" color="primary">
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Rules;
